previewCss:
.darma-loader-darma-custom-200 {
  color: #0f766e;
--s: 17px;
width: calc(var(--s)*2.33);
aspect-ratio: 1;
display: flex;
justify-content: space-between;
}
.darma-loader-darma-custom-200::before,
.darma-loader-darma-custom-200::after {
content: "";
width: var(--s);
--_g: no-repeat radial-gradient(farthest-side,currentColor 94%,#0000);
background:
var(--_g) top,
var(--_g) bottom;
background-size: 100% var(--s);
transform-origin: 50% calc(100% - var(--s)/2);
animation: darma-loader-darma-custom-200-l30 1s infinite;
}
.darma-loader-darma-custom-200::after {
transform-origin: 50% calc(var(--s)/2);
}
@keyframes darma-loader-darma-custom-200-l30 {
70%,100% {transform:rotate(-270deg)}
}

